              axis: "y" as DraggableAxis,
              defaultPosition: { x: 0, y: position },
              handle: `handle-y-${item}`,
              key: `y-${item}`,
              lineStyle: {
                width: imageSize.width,
                height: 1,
                zIndex: 100,
              },
            };
          })
        );
    } else {
      draggableListData.value = [];
    }
    console.log("draggableListData", draggableListData.value);
  }
